   194	    private List<JsonNode> queryWithExpression(ConcurrentSkipListMap<String, JsonNode> items,
   195	                                                String pkName, String skName,
   196	                                                String expression,
   197	                                                JsonNode expressionAttrValues,
   198	                                                JsonNode exprAttrNames) {
   199	        expression = trimBalancedOuterParens(expression);
   200	        List<JsonNode> results = new ArrayList<>();
   201	
   202	        // Parse simple expressions: "pk = :val" or "pk = :val AND sk begins_with :prefix"
   203	        String[] parts = expression.split("\\s+[Aa][Nn][Dd]\\s+", 2);
   204	        String pkExpression = trimBalancedOuterParens(parts[0].trim());
   205	        String skExpression = parts.length > 1 ? trimBalancedOuterParens(parts[1].trim()) : null;
   206	
   207	        // Extract pk attr name from expression (may use #alias)
   208	        String pkAttrInExpr = pkExpression.split("\\s*=\\s*")[0].trim();
   209	        String resolvedPkName = resolveAttributeName(pkAttrInExpr, exprAttrNames);
   210	
   211	        // Extract pk value
   212	        String pkPlaceholder = extractPlaceholder(pkExpression);
   213	        String pkValue = pkPlaceholder != null && expressionAttrValues != null
   214	                ? extractScalarValue(expressionAttrValues.get(pkPlaceholder))
   215	                : null;
   216	
   217	        for (JsonNode item : items.values()) {
   218	            if (!item.has(resolvedPkName)) continue;
   219	            if (pkValue != null && !matchesAttributeValue(item.get(resolvedPkName), pkValue)) {
   220	                continue;
   221	            }
   222	
   223	            if (skExpression != null && skName != null) {
   224	                if (!matchesSkExpression(item.get(skName), skExpression, expressionAttrValues)) {
   225	                    continue;
   226	                }
   227	            }
   228	
   229	            results.add(item);
   230	        }
   231	
   232	        return results;
   233	    }
