   235	    private boolean matchesSkExpression(JsonNode skValue, String expression, JsonNode exprValues) {
   236	        expression = trimBalancedOuterParens(expression);
   237	        String actual = extractScalarValue(skValue);
   238	        if (actual == null) return false;
   239	
   240	        String exprLower = expression.toLowerCase();
   241	        if (exprLower.contains("begins_with")) {
   242	            String placeholder = extractPlaceholder(expression);
   243	            String prefix = placeholder != null && exprValues != null
   244	                    ? extractScalarValue(exprValues.get(placeholder)) : null;
   245	            return prefix != null && actual.startsWith(prefix);
   246	        }
   247	
   248	        if (exprLower.contains(" between ")) {
   249	            int betweenIdx = exprLower.indexOf(" between ");
   250	            int andIdx = exprLower.indexOf(" and ", betweenIdx + " between ".length());
   251	            if (andIdx < 0) return false;
   252	
   253	            String lowerExpr = expression.substring(betweenIdx + " between ".length(), andIdx).trim();
   254	            String upperExpr = expression.substring(andIdx + " and ".length()).trim();
   255	            String lowerPlaceholder = lowerExpr.startsWith(":") ? lowerExpr.split("\\s+")[0] : null;
   256	            String upperPlaceholder = upperExpr.startsWith(":") ? upperExpr.split("\\s+")[0] : null;
   257	            String lower = lowerPlaceholder != null && exprValues != null
   258	                    ? extractScalarValue(exprValues.get(lowerPlaceholder)) : null;
   259	            String upper = upperPlaceholder != null && exprValues != null
   260	                    ? extractScalarValue(exprValues.get(upperPlaceholder)) : null;
   261	            if (lower == null || upper == null) return false;
   262	            return compareValues(actual, lower) >= 0 && compareValues(actual, upper) <= 0;
   263	        }
   264	
   265	        // Detect comparison operator
   266	        String[] operators = {"<>", "<=", ">=", "=", "<", ">"};
   267	        for (String op : operators) {
   268	            int opIdx = expression.indexOf(op);
   269	            if (opIdx > 0) {
   270	                String right = expression.substring(opIdx + op.length()).trim();
   271	                String placeholder = right.startsWith(":") ? right.split("\\s+")[0] : null;
   272	                String expected = placeholder != null && exprValues != null
   273	                        ? extractScalarValue(exprValues.get(placeholder)) : null;
   274	                if (expected == null) return false;
   275	                return switch (op) {
   276	                    case "=" -> actual.equals(expected);
   277	                    case "<>" -> !actual.equals(expected);
   278	                    case ">=" -> actual.compareTo(expected) >= 0;
   279	                    case "<=" -> actual.compareTo(expected) <= 0;
   280	                    case ">" -> actual.compareTo(expected) > 0;
   281	                    case "<" -> actual.compareTo(expected) < 0;
   282	                    default -> true;
   283	                };
   284	            }
   285	        }
   286	        return true;
   287	    }
