   289	    private String extractPlaceholder(String expression) {
   290	        // Find :placeholder in expression
   291	        int idx = expression.indexOf(':');
   292	        if (idx < 0) return null;
   293	        int end = idx + 1;
   294	        while (end < expression.length() && (Character.isLetterOrDigit(expression.charAt(end)) || expression.charAt(end) == '_')) {
   295	            end++;
   296	        }
   297	        return expression.substring(idx, end);
   298	    }
