   300	    private String trimBalancedOuterParens(String expression) {
   301	        if (expression == null) return null;
   302	        String trimmed = expression.trim();
   303	        while (trimmed.length() >= 2 && trimmed.startsWith("(") && trimmed.endsWith(")")
   304	                && hasBalancedOuterParens(trimmed)) {
   305	            trimmed = trimmed.substring(1, trimmed.length() - 1).trim();
   306	        }
   307	        return trimmed;
   308	    }
