   310	    private boolean hasBalancedOuterParens(String expression) {
   311	        int depth = 0;
   312	        for (int i = 0; i < expression.length(); i++) {
   313	            char c = expression.charAt(i);
   314	            if (c == '(') {
   315	                depth++;
   316	            } else if (c == ')') {
   317	                depth--;
   318	                if (depth == 0 && i < expression.length() - 1) {
   319	                    return false;
   320	                }
   321	                if (depth < 0) {
   322	                    return false;
   323	                }
   324	            }
   325	        }
   326	        return depth == 0;
   327	    }
