package io.github.hectorvent.floci.services.dynamodb;

import io.github.hectorvent.floci.core.common.RegionResolver;
import io.github.hectorvent.floci.core.storage.InMemoryStorage;
import io.github.hectorvent.floci.core.storage.StorageBackend;
import io.github.hectorvent.floci.services.dynamodb.model.*;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.util.List;
import java.util.Map;

/**
 * Quick reproduction script for the DDB streams persistence issue.
 * This demonstrates that when a DynamoDbService is re-created from persisted
 * table data, streams are NOT restored in DynamoDbStreamService.
 */
public class ReproTest {
    public static void main(String[] args) {
        ObjectMapper mapper = new ObjectMapper();

        // Step 1: Create a tableStore with a table that has stream info
        InMemoryStorage<String, TableDefinition> tableStore = new InMemoryStorage<>();

        TableDefinition table = new TableDefinition("TestTable",
                List.of(new KeySchemaElement("pk", "HASH")),
                List.of(new AttributeDefinition("pk", "S")),
                "us-east-1", "000000000000");
        table.setStreamEnabled(true);
        table.setStreamArn("arn:aws:dynamodb:us-east-1:000000000000:table/TestTable/stream/2024-01-01T00:00:00.000");
        table.setStreamViewType("NEW_AND_OLD_IMAGES");

        tableStore.put("us-east-1::TestTable", table);

        // Step 2: Create a new DynamoDbStreamService (simulating restart)
        DynamoDbStreamService streamService = new DynamoDbStreamService(mapper);

        // Step 3: Create a new DynamoDbService with the persisted data
        DynamoDbService service = new DynamoDbService(tableStore, null,
                new RegionResolver("us-east-1", "000000000000"), streamService);

        // Step 4: Check if streams are available
        List<StreamDescription> streams = streamService.listStreams(null, "us-east-1");

        if (streams.isEmpty()) {
            System.out.println("BUG REPRODUCED: Stream list is empty after restoring from persisted data!");
        } else {
            System.out.println("Stream found: " + streams.get(0).getStreamArn());
        }

        // Also verify we can describe the table with stream info
        TableDefinition restored = service.describeTable("TestTable");
        System.out.println("Table streamEnabled: " + restored.isStreamEnabled());
        System.out.println("Table streamArn: " + restored.getStreamArn());
    }
}
