        this.streamService = streamService;
        loadPersistedItems();
        loadPersistedStreams();
    }

    private void loadPersistedStreams() {
        if (streamService == null) return;
        for (String key : tableStore.keys()) {
            tableStore.get(key).ifPresent(table -> {
                if (table.isStreamEnabled() && table.getStreamArn() != null) {
                    String[] parts = parseStorageKey(key);
                    streamService.restoreStream(table.getTableName(), table.getStreamArn(),
                            table.getStreamViewType(), parts[0]);
                }
            });
        }
    }

    private static String[] parseStorageKey(String key) {
        int idx = key.indexOf("::");
        return new String[]{key.substring(0, idx), key.substring(idx + 2)};
    }

